import React from "react";
import { connect } from "react-redux";
import { getLanguages } from "../../actions/language";
import ItemList from "./ItemList.view";
import { filter } from "../../utils/search";
import { getCustomItems } from "./utils";

class MyLanguages extends React.Component {
    constructor(props) {
        super(props);
        this.state = {
            query: ""
        }
    }
    componentDidMount() {
        this.props.getLanguages()
        this.searchRef.focus()
    }
    getFilteredLanguages = () => {
        let languages = this.props.allIds.map(id => this.props.byIds[id]).filter(x => !x.createdByUser)
        let customLanguages = getCustomItems(this.props.languages, languages)
        let combined = customLanguages.concat(languages);
        return filter(this.state.query, combined).map(x => {
            if (this.props.common.languages[x.name]) {
                return {
                    ...x,
                    show: this.props.common.languages[x.name][this.props.app_lang]
                }
            }
            return x
        })
    }
    resetQuery = () => this.setState({ query: "" })
    customAddLanguage = language_name => () => {
        this.props.addLanguage(language_name)
        if (this.state.query === language_name) this.resetQuery()
    }
    getAllowedOperation = (language_name, defaultOnClick = true) => {
        let alreadyExists = this.props.languages.indexOf(language_name) !== -1
        if (alreadyExists) {
            let div = <span onClick={defaultOnClick && (() => this.props.removeLanguage(language_name))}>-</span>
            return { type: "-", div, onClick: () => this.props.removeLanguage(language_name) }
        }
        else {
            let div = <span onClick={defaultOnClick && this.customAddLanguage(language_name)}>+</span>
            return { type: "+", div, onClick: this.customAddLanguage(language_name) }
        }
    }
    createCustomLanguage = () => (
        <React.Fragment>
            <div
                onClick={this.getAllowedOperation(this.state.query, false).onClick}
                style={{ cursor: "pointer" }}
                className="list-item"
            ><p>Create "{this.state.query}"</p>
                {this.getAllowedOperation(this.state.query, false).div}
            </div>
        </React.Fragment>
    )
    searchOnKeyDown = e => {
        let languages = this.getFilteredLanguages();
        if (!languages.length) {
            if (e.key === "Enter") {
                this.customAddLanguage(this.state.query)();
            }
        }
    }
    render() {
        console.log({ props: this.props })
        return (
            <React.Fragment>
                <div className="background-title mb5">
                    <h1>{this.props.getTrans(this.props.translations.text_30)}</h1>
                    <p className="shadow__title">setup your account</p>
                </div>
                <div className="flex-grow input__group skills__input-group">
                    <div className="search__input mb40">
                        <span><img src="/images/new/search.png" alt="" /></span>
                        <input
                            type="text"
                            ref={ref => this.searchRef = ref}
                            placeholder={this.props.getTrans(this.props.translations.text_31)}
                            value={this.state.query}
                            onChange={e => this.setState({ query: e.target.value })}
                            onKeyDown={this.searchOnKeyDown}
                        />
                    </div>
                    <div className="items-added">
                        {!this.props.loading && this.getFilteredLanguages()
                            .filter(language => this.getAllowedOperation(language.name).type == "-")
                            .map(language => (
                                <div
                                    className="item-added"
                                >
                                    <p>{language.show || language.name}</p>
                                    {this.getAllowedOperation(language.name).div}
                                </div>

                            ))
                        }
                    </div>
                    <div className="list-items">
                        {!this.props.loading && this.getFilteredLanguages()
                            .filter(language => this.getAllowedOperation(language.name).type == "+")
                            .map(language => {
                                return (
                                    <React.Fragment>
                                        <div
                                            onClick={this.getAllowedOperation(language.name, false).onClick}
                                            style={{ cursor: "pointer" }} 
                                             className="list-item"
                                        ><p>{language.show || language.name}</p>
                                            {this.getAllowedOperation(language.name,false).div}
                                        </div>
                                    </React.Fragment>
                                )
                            })}
                        {
                            !this.props.loading && !this.getFilteredLanguages().length && this.state.query &&
                            this.createCustomLanguage()
                        }
                    </div>
                </div>

            </React.Fragment>
        )
    }
}

const mapStateToProps = state => ({
    byIds: state.languages.byIds,
    allIds: state.languages.allIds,
    loading: state.languages.loading
})

export default connect(mapStateToProps, { getLanguages })(MyLanguages);